import pandas as pd
from glob import glob
for prefix, date_col, extra in [
    ('sales_transaction','sales_date',['store_id','product_id','units_sold','revenue','promo_price']),
    ('store_order','order_date',['store_id','product_id','ordered_units']),
    ('inventory_status','inventory_date',['store_id','product_id','stock_units','out_of_stock']),
    ('store_traffic','traffic_date',['store_id','customer_count']),
    ('store_promotion',None,['store_id','promotion_id','product_id','display_active','discounted_price']),
    ('shelf_audit',None,['visit_id','product_id']),
    ('competitor_audit',None,['visit_id','competitor_brand']),
]:
    files=sorted(glob(f'{prefix}_*.csv'))
    rows=0
    mins=[]; maxs=[]
    uniq_store=set(); uniq_prod=set(); uniq_vis=set(); uniq_promo=set()
    for f in files:
        usecols=list(extra)
        if date_col: usecols=[date_col]+usecols
        df=pd.read_csv(f, usecols=usecols)
        rows += len(df)
        if date_col:
            mins.append(df[date_col].min())
            maxs.append(df[date_col].max())
        if 'store_id' in df: uniq_store.update(df['store_id'].unique())
        if 'product_id' in df: uniq_prod.update(df['product_id'].unique())
        if 'visit_id' in df: uniq_vis.update(df['visit_id'].unique())
        if 'promotion_id' in df: uniq_promo.update(df['promotion_id'].unique())
    out={'rows':rows}
    if mins: out['date_min']=min(mins); out['date_max']=max(maxs)
    if uniq_store: out['stores']=len(uniq_store)
    if uniq_prod: out['products']=len(uniq_prod)
    if uniq_vis: out['visits']=len(uniq_vis)
    if uniq_promo: out['promotions']=len(uniq_promo)
    print(prefix, out)
